def acache(f):
    "Cache results of async function `f`"
    cache = {}
    @wraps(f)
    async def _inner(*args, **kwargs):
        key = (args, tuple(sorted(kwargs.items())))
        if key not in cache: cache[key] = await f(*args, **kwargs)
        return cache[key]
    _inner.cache_clear = cache.clear
    return _inner

